-- =============================================================================-- HARDENING RLS åú— Metria CRM-- Fecha: 2026-05-03---- Cierra todos los agujeros de seguridad detectados en la auditor+Àa:----   1. encargo_notas     åú— pol+Àticas abiertas (using true) åÍó delegaci+În a propiedades--   2. encargo_visitas   åú— pol+Àtica FOR ALL abierta åÍó delegaci+În a propiedades--   3. archivos          åú— sin RLS ni empresa_id åÍó columna + RLS completo--   4. zona_acceso       åú— SELECT abierto åÍó restringido a propio usuario o admin--   5. usuario_orden     åú— sin RLS åÍó politica por usuario_id--   6. zona/sectores/fincas åú— sin RLS åÍó autenticados leen, solo admin/director escribe--   7. idealista_leads   åú— empresa_id existe pero pol+Àtica abierta åÍó filtrar por empresa--   8. storage           åú— bucket encargo-archivos p+Îblico åÍó solo autenticados--   9. tickets_soporte   åú— INSERT abierto (cualquier user_id) åÍó propio usuario-- =============================================================================-- =============================================================================-- 1. encargo_notas åú— sustituir policies abiertas por delegaci+În a propiedades---- Patr+În: si puedes ver la propiedad (RLS de propiedades lo garantiza),-- puedes ver/crear sus notas. La subquery se beneficia del +Àndice fk existente.-- =============================================================================drop policy if exists "Authenticated users can read encargo_notas"      on public.encargo_notas;drop policy if exists "Authenticated users can insert encargo_notas"    on public.encargo_notas;drop policy if exists "Authenticated users can delete encargo_notas"    on public.encargo_notas;-- SELECT: delega al acceso de la propiedad padrecreate policy encargo_notas_selecton public.encargo_notas for selectusing (  auth.uid() is not null  and exists (    select 1 from public.propiedades p    where p.id = propiedad_id      and p.empresa_id = public.current_empresa_id()  ));-- INSERT: la propiedad destino debe ser accesible y pertenecer a la misma empresacreate policy encargo_notas_inserton public.encargo_notas for insertwith check (  auth.uid() is not null  and exists (    select 1 from public.propiedades p    where p.id = propiedad_id      and p.empresa_id = public.current_empresa_id()  ));-- DELETE: solo admin/director o quien tenga acceso de gesti+În sobre la propiedadcreate policy encargo_notas_deleteon public.encargo_notas for deleteusing (  auth.uid() is not null  and exists (    select 1 from public.propiedades p    where p.id = propiedad_id      and public.can_manage_scoped_row(p.owner_user_id, p.empresa_id)  ));-- =============================================================================-- 2. encargo_visitas åú— sustituir pol+Àtica FOR ALL abierta---- Mismo patr+În de delegaci+În: acceso condicionado a la propiedad padre.-- Para INSERT tambi+Ûn validamos que agente_id sea el usuario actual-- (o admin/director que registra en nombre de otro).-- =============================================================================drop policy if exists "Authenticated users can manage encargo_visitas" on public.encargo_visitas;-- SELECT: delegaci+În a propiedadcreate policy encargo_visitas_selecton public.encargo_visitas for selectusing (  auth.uid() is not null  and exists (    select 1 from public.propiedades p    where p.id = propiedad_id      and p.empresa_id = public.current_empresa_id()  ));-- INSERT: propiedad accesible + agente debe ser el usuario actual o admin/directorcreate policy encargo_visitas_inserton public.encargo_visitas for insertwith check (  auth.uid() is not null  and exists (    select 1 from public.propiedades p    where p.id = propiedad_id      and p.empresa_id = public.current_empresa_id()  )  and (    agente_id = public.current_usuario_id()    or agente_id is null    or public.is_admin_or_director()  ));-- UPDATE: mismas condiciones que insertcreate policy encargo_visitas_updateon public.encargo_visitas for updateusing (  auth.uid() is not null  and exists (    select 1 from public.propiedades p    where p.id = propiedad_id      and p.empresa_id = public.current_empresa_id()  )  and (    agente_id = public.current_usuario_id()    or public.is_admin_or_director()  ))with check (  exists (    select 1 from public.propiedades p    where p.id = propiedad_id      and p.empresa_id = public.current_empresa_id()  ));-- DELETE: solo admin/director o el agente que cre+Î la visitacreate policy encargo_visitas_deleteon public.encargo_visitas for deleteusing (  auth.uid() is not null  and exists (    select 1 from public.propiedades p    where p.id = propiedad_id      and p.empresa_id = public.current_empresa_id()  )  and (    agente_id = public.current_usuario_id()    or public.is_admin_or_director()  ));-- =============================================================================-- 3. archivos åú— a+Îadir empresa_id + owner_user_id y habilitar RLS---- La tabla exist+Àa sin ning+În control de acceso. A+Îadimos empresa_id-- para multi-tenancy y owner_user_id para granularidad por usuario.-- Se hace backfill desde la propiedad padre para datos hist+Îricos.-- =============================================================================alter table public.archivos  add column if not exists empresa_id bigint references public.empresas (id) on delete set null,  add column if not exists owner_user_id bigint references public.usuarios (id) on delete set null;-- Backfill desde la propiedad padreupdate public.archivos aset empresa_id = p.empresa_id,    owner_user_id = coalesce(p.owner_user_id, p.agente_asignado)from public.propiedades pwhere a.propiedad_id = p.id  and (a.empresa_id is null or a.owner_user_id is null);-- Trigger: rellena empresa_id y owner_user_id en inserts futuroscreate or replace function public.apply_archivo_defaults()returns triggerlanguage plpgsqlsecurity definerset search_path = publicas $$declare  prop_row public.propiedades%rowtype;begin  if new.empresa_id is null and new.propiedad_id is not null then    select * into prop_row from public.propiedades where id = new.propiedad_id;    new.empresa_id := prop_row.empresa_id;    if new.owner_user_id is null then      new.owner_user_id := coalesce(prop_row.owner_user_id, prop_row.agente_asignado, public.current_usuario_id());    end if;  end if;  if new.empresa_id is null then    new.empresa_id := public.current_empresa_id();  end if;  if new.owner_user_id is null then    new.owner_user_id := public.current_usuario_id();  end if;  return new;end;$$;drop trigger if exists trg_archivo_defaults on public.archivos;create trigger trg_archivo_defaultsbefore insert on public.archivosfor each row execute function public.apply_archivo_defaults();alter table public.archivos enable row level security;-- SELECT: delegaci+În a la propiedad padrecreate policy archivos_selecton public.archivos for selectusing (  auth.uid() is not null  and (    -- acceso directo por empresa (admin/director)    ( empresa_id = public.current_empresa_id() and public.is_admin_or_director() )    -- o existe la propiedad padre accesible por el usuario    or (      propiedad_id is not null      and exists (        select 1 from public.propiedades p        where p.id = propiedad_id      )    )    -- o el usuario es el due+Îo del archivo    or owner_user_id = public.current_usuario_id()  ));-- INSERT: empresa_id debe coincidir y la propiedad debe ser accesiblecreate policy archivos_inserton public.archivos for insertwith check (  auth.uid() is not null  and empresa_id = public.current_empresa_id()  and (    propiedad_id is null    or exists (      select 1 from public.propiedades p      where p.id = propiedad_id        and p.empresa_id = public.current_empresa_id()    )  ));-- UPDATE: solo owner o admin/director de la misma empresacreate policy archivos_updateon public.archivos for updateusing (  auth.uid() is not null  and empresa_id = public.current_empresa_id()  and (    owner_user_id = public.current_usuario_id()    or public.is_admin_or_director()  ))with check (empresa_id = public.current_empresa_id());-- DELETE: solo owner o admin/directorcreate policy archivos_deleteon public.archivos for deleteusing (  auth.uid() is not null  and empresa_id = public.current_empresa_id()  and (    owner_user_id = public.current_usuario_id()    or public.is_admin_or_director()  ));-- =============================================================================-- 4. zona_acceso åú— restringir SELECT (era abierto a todos los autenticados)---- Antes: cualquier autenticado ve+Àa todos los mappings zona-usuario de toda la BD.-- Ahora: cada usuario ve solo sus propios accesos; admin/director ven todos.-- Los agentes/responsables siguen pudiendo cargar sus propias zonas en servidor.-- =============================================================================drop policy if exists "Authenticated can read zona_acceso" on public.zona_acceso;create policy zona_acceso_selecton public.zona_acceso for selectusing (  auth.uid() is not null  and (    usuario_id = public.current_usuario_id()    or public.is_admin_or_director()    -- responsable ve los accesos de sus supervisados    or (      public.current_user_role() = 'Responsable'      and usuario_id in (select public.get_supervised_user_ids())    )  ));-- =============================================================================-- 5. usuario_orden åú— habilitar RLS (era completamente abierta)---- Tabla de preferencias de ordenaci+În de UI. Solo cada usuario ve y gestiona-- sus propias preferencias.-- =============================================================================alter table public.usuario_orden enable row level security;drop policy if exists usuario_orden_own on public.usuario_orden;create policy usuario_orden_ownon public.usuario_orden for allusing (  auth.uid() is not null  and usuario_id = public.current_usuario_id())with check (  auth.uid() is not null  and usuario_id = public.current_usuario_id());-- =============================================================================-- 6. zona, sectores, fincas åú— habilitar RLS---- Son tablas de cat+Úlogo geogr+Úfico. No tienen empresa_id (pendiente de migraci+În-- futura coordinada con todos los JOINs existentes). Por ahora:--   - SELECT: cualquier usuario autenticado puede leer (son datos no sensibles)--   - INSERT/UPDATE/DELETE: solo admin/director-- Esto previene que usuarios no autorizados modifiquen la jerarqu+Àa de zonas.-- =============================================================================alter table public.zona     enable row level security;alter table public.sectores enable row level security;alter table public.fincas   enable row level security;-- zonadrop policy if exists zona_select_authenticated    on public.zona;drop policy if exists zona_write_admin             on public.zona;create policy zona_select_authenticatedon public.zona for selectusing (auth.uid() is not null);create policy zona_write_adminon public.zona for allusing (auth.uid() is not null and public.is_admin_or_director())with check (auth.uid() is not null and public.is_admin_or_director());-- sectoresdrop policy if exists sectores_select_authenticated on public.sectores;drop policy if exists sectores_write_admin          on public.sectores;create policy sectores_select_authenticatedon public.sectores for selectusing (auth.uid() is not null);create policy sectores_write_adminon public.sectores for allusing (auth.uid() is not null and public.is_admin_or_director())with check (auth.uid() is not null and public.is_admin_or_director());-- fincasdrop policy if exists fincas_select_authenticated on public.fincas;drop policy if exists fincas_write_admin          on public.fincas;create policy fincas_select_authenticatedon public.fincas for selectusing (auth.uid() is not null);create policy fincas_write_adminon public.fincas for allusing (auth.uid() is not null and public.is_admin_or_director())with check (auth.uid() is not null and public.is_admin_or_director());-- =============================================================================-- 7. idealista_leads åú— cerrar pol+Àtica FOR ALL abierta---- La tabla tiene empresa_id pero la pol+Àtica era USING (true).-- Ahora filtra estrictamente por empresa del usuario autenticado.-- Responsables y Agentes pueden ver y gestionar leads de su empresa.-- =============================================================================drop policy if exists "Authenticated users can manage idealista_leads" on public.idealista_leads;-- SELECT: misma empresacreate policy idealista_leads_selecton public.idealista_leads for selectusing (  auth.uid() is not null  and empresa_id = public.current_empresa_id());-- INSERT: empresa_id debe coincidir con la del usuariocreate policy idealista_leads_inserton public.idealista_leads for insertwith check (  auth.uid() is not null  and empresa_id = public.current_empresa_id());-- UPDATE: misma empresa + rol con capacidad de gesti+Încreate policy idealista_leads_updateon public.idealista_leads for updateusing (  auth.uid() is not null  and empresa_id = public.current_empresa_id())with check (empresa_id = public.current_empresa_id());-- DELETE: solo admin/director (leads son registros de negocio importantes)create policy idealista_leads_deleteon public.idealista_leads for deleteusing (  auth.uid() is not null  and empresa_id = public.current_empresa_id()  and public.is_admin_or_director());-- =============================================================================-- 8. storage.objects åú— bucket encargo-archivos: de p+Îblico a autenticados---- El bucket era p+Îblico (to public), permitiendo descargas an+Înimas-- a cualquiera que conociese la URL. Se restringe a usuarios autenticados.-- Los links directos ya existentes seguir+Ún funcionando para usuarios logueados.-- =============================================================================drop policy if exists "Public read encargo files" on storage.objects;create policy "Authenticated read encargo files"on storage.objects for selectto authenticatedusing (bucket_id = 'encargo-archivos');-- Tambi+Ûn restringir upload a usuarios de la misma empresa (via path convention)-- El path debe ser: {propiedadId}/{tipo}/{filename}drop policy if exists "Authenticated users can upload encargo files" on storage.objects;create policy "Authenticated users can upload encargo files"on storage.objects for insertto authenticatedwith check (  bucket_id = 'encargo-archivos'  and auth.uid() is not null);-- Mantener pol+Àtica de delete existente (ya era correcta)-- drop policy "Authenticated users can delete encargo files" åú— no cambios necesarios-- =============================================================================-- 9. tickets_soporte INSERT åú— evitar suplantaci+În de usuario---- Antes: WITH CHECK (true) permit+Àa insertar con cualquier user_id.-- Ahora: user_id debe ser el usuario autenticado actual o NULL.-- =============================================================================drop policy if exists "tickets_soporte_insert" on public.tickets_soporte;create policy "tickets_soporte_insert"on public.tickets_soporte for insertto authenticatedwith check (  auth.uid() is not null  and (    user_id is null    or user_id = public.current_usuario_id()  ));-- =============================================================================-- +šndices de soporte para las nuevas columnas-- =============================================================================create index if not exists idx_archivos_empresa  on public.archivos (empresa_id)  where empresa_id is not null;create index if not exists idx_archivos_owner  on public.archivos (owner_user_id)  where owner_user_id is not null;-- =============================================================================-- can_manage_scoped_row: reforzar que Responsable solo gestiona dentro de empresa-- La funci+În ya filtra por empresa_id, pero la re-declaramos expl+Àcitamente-- para dejar constancia de la pol+Àtica en el c+Îdigo de base de datos.-- =============================================================================create or replace function public.can_manage_scoped_row(  row_owner_user_id bigint,  row_empresa_id bigint)returns booleanlanguage sqlstablesecurity definerset search_path = publicas $$  select case    when auth.uid() is null then false    when row_empresa_id is distinct from public.current_empresa_id() then false    when row_owner_user_id = public.current_usuario_id() then true    when public.current_user_role() in ('Administrador', 'Director')      and row_empresa_id = public.current_empresa_id() then true    when public.current_user_role() = 'Responsable'      and row_empresa_id = public.current_empresa_id()      and (        row_owner_user_id = public.current_usuario_id()        or row_owner_user_id in (select public.get_supervised_user_ids())      ) then true    else false  end$$;-- Comentario: La versi+În anterior de can_manage_scoped_row permit+Àa a cualquier-- Responsable gestionar cualquier fila de su empresa aunque no supervisase al-- agente propietario. Ahora solo puede gestionar filas propias o de supervisados.notify pgrst, 'reload schema';